INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('693230a0-d462-46dc-9108-9752df61caba', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Journeys Workflow Builder$q$, $q$Visual, branching campaign builder for creating multi-step, condition-based messaging journeys triggered by customer behavior rather than fixed schedules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Multichannel Messaging$q$, $q$Send messages via email, push notifications, SMS, in-app messages, and webhooks from a single workflow, coordinating timing and logic across channels.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Behavioral Triggers$q$, $q$Campaigns can start, branch, or exit based on real-time customer actions and events, not just static list membership or a fixed send date.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Data Pipelines (Customer Data Platform)$q$, $q$A built-in data layer that ingests and unifies events and profile attributes from web, mobile, CRM, and data warehouse sources for use in campaigns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Dynamic Segmentation$q$, $q$Build audience segments that combine behavioral events with demographic or account-level attributes, updating automatically as new data arrives.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$A/B Testing$q$, $q$Test subject lines, message content, or send timing within a workflow to compare performance and improve results over time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Liquid Personalization$q$, $q$Use Liquid templating logic to personalize message content dynamically based on individual customer data and attributes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Broadcast Campaigns$q$, $q$Send one-off announcements, newsletters, or time-bound promotions outside of the always-on automated journeys.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Reporting & Analytics$q$, $q$Dashboards track deliverability, opens, clicks, and conversion against campaign and workflow-level goals.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Developer API & SDKs$q$, $q$A REST API, webhooks, and mobile SDKs let engineering teams integrate event tracking and messaging directly into product code.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Strong behavior-triggered automation that reacts to real-time customer actions instead of only static lists$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Genuine multichannel messaging (email, push, SMS, in-app) managed from a single workflow builder$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Built-in customer data layer makes event-based segmentation possible without a separate data platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$API and SDK depth suit teams that want to embed messaging directly into product experiences$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Detailed reporting on deliverability, engagement, and campaign-level conversion$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Requires meaningful event tracking and data setup before the platform delivers its full value$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Steeper learning curve than simple drag-and-drop email tools, especially for non-technical marketers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Pricing scales with contacts and message volume, which can get costly as an audience grows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Fewer out-of-the-box e-commerce templates and integrations compared to commerce-focused competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Getting the most from the platform generally depends on having developer or data support available$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$What is Customer.io used for?$q$, $q$Customer.io is used to send automated, behavior-triggered messages across email, push, SMS, and in-app channels, commonly for onboarding, lifecycle, and retention campaigns that respond to how customers actually use a product or website.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Is Customer.io only for email marketing?$q$, $q$No. While email is one of its core channels, Customer.io also supports push notifications, SMS, in-app messages, and webhooks, letting teams orchestrate a single customer journey across multiple channels rather than managing email in isolation.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Does Customer.io require developer involvement?$q$, $q$Getting meaningful value from Customer.io generally requires tracking product or website events and connecting customer data, so having at least some developer or data support is common, though non-technical teams can build and edit campaigns once that data is flowing.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Does Customer.io offer a free trial?$q$, $q$Customer.io is a paid platform that offers a free trial period so teams can test workflows and messaging before committing. Ongoing pricing is usage-based, tied to the number of contacts and messages sent, rather than a single flat fee.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$How is Customer.io different from a typical email marketing tool?$q$, $q$Traditional email tools are usually built around static contact lists and scheduled broadcasts, while Customer.io is built around real-time event data, so campaigns can react immediately to individual customer behavior across several channels instead of sending only on a fixed schedule.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$SaaS onboarding and activation$q$, $q$Trigger step-by-step onboarding emails and in-app messages based on whether a new signup completes key setup actions, nudging users toward activation.$q$, $q$SaaS and product-led growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Lifecycle and retention campaigns$q$, $q$Automatically re-engage users who show signs of reduced activity, and follow up across email, push, and in-app messaging based on real usage patterns.$q$, $q$Customer success and lifecycle marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Behavioral e-commerce messaging$q$, $q$Send cart-abandonment reminders, browse-abandonment follow-ups, and post-purchase messages triggered by shopping behavior events.$q$, $q$E-commerce and DTC marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Multichannel product announcements$q$, $q$Coordinate feature-announcement or release campaigns across email, in-app messages, and push notifications from a single workflow.$q$, $q$Product marketing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Essentials$q$, $q$Usage-based; contact sales for a quote$q$, $q$Monthly or annual$q$, $q$["Core Journeys workflow builder","Email, push, and in-app messaging","Basic segmentation and reporting","API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Premium$q$, $q$Custom / usage-based; contact sales$q$, $q$Monthly or annual$q$, $q$["Advanced segmentation and A/B testing","SMS and additional messaging channels","Data Pipelines / customer data platform features","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Enterprise$q$, $q$Custom / contact sales$q$, $q$Annual$q$, $q$["Custom contract and volume-based pricing","Dedicated support and onboarding","Advanced security and compliance options","Expanded API and data limits"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Customer.io is a customer messaging and marketing automation platform that helps companies send targeted, data-driven communications across email, push notifications, SMS, in-app messages, and other channels. Instead of relying primarily on static contact lists, the platform is organized around real-time behavioral and event data, so a message can be triggered the moment a specific customer takes, or fails to take, an action inside a product, app, or website, rather than waiting for a scheduled broadcast.$q$, $q$Founded in 2012, Customer.io began as a simple transactional and triggered email tool and has since grown into a broader customer engagement suite that pairs a visual workflow builder with an underlying customer data layer and multichannel delivery. Its workflow editor, called Journeys, lets marketing, growth, and product teams map out branching campaigns with delays, conditional splits, and multiple channels, all responding to how individual customers actually behave rather than a single static list segment.$q$, $q$Because of this data-first design, Customer.io is usually categorized as a behavioral or data-driven messaging platform rather than a simple bulk email sender. It's commonly used by teams that already track meaningful product or website events and want those events to directly drive personalized, timely messaging, and it's often adopted specifically because generic list-based email tools can't easily react to individual customer behavior in real time.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$who-its-for$q$, $q$Who Customer.io Is For$q$, 2, ARRAY[$q$Customer.io is best suited to SaaS and other digital-product companies that want to turn user behavior into automated messaging, for example, triggering an onboarding sequence when a new signup stalls partway through setup, or following up when a customer abandons an in-progress workflow. Product-led growth and lifecycle teams frequently rely on it to nudge trial users toward activation milestones and to re-engage users who show signs of dropping off.$q$, $q$It also suits marketing and lifecycle teams that need to coordinate messaging across more than one channel at once, such as following an unopened email with a push notification or an in-app message a day later, without stitching together several separate single-channel tools and trying to keep their logic and timing in sync manually.$q$, $q$Because the platform is built around event tracking and APIs, it works best for organizations with at least some engineering or data support available, whether that means instrumenting product events, connecting a data warehouse or a tool like Segment, or maintaining message templates that use Liquid logic for dynamic personalization based on customer attributes and history.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small businesses or solo marketers who just want the simplest possible way to send a newsletter or basic drip sequence, with no need for event-based triggers or behavioral segmentation, may find Customer.io more platform than they actually need, and might be better served by a lighter, more purely template-driven email tool.$q$, $q$E-commerce brands whose main requirement is pre-built commerce functionality, ready-made abandoned cart flows, product recommendation blocks, and one-click storefront integrations, may find dedicated e-commerce marketing platforms a closer out-of-the-box fit, since Customer.io's commerce-related messaging is more general-purpose and typically requires custom event tracking and template work rather than a plug-and-play setup.$q$, $q$Teams with no developer or data support at all may also struggle to get full value from the platform, since meaningful use generally depends on tracking real product or website events and syncing customer profile data, rather than relying purely on manually uploaded contact lists as with simpler email tools.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Customer.io is Journeys, a visual workflow builder for creating branching campaigns that combine time delays, conditional splits, and sends across multiple channels, all triggered by customer behavior or attribute changes. Workflows can run continuously in the background for lifecycle stages like onboarding or renewal, while one-off broadcast campaigns handle announcements, newsletters, or time-bound promotions.$q$, $q$The platform includes its own customer data layer, commonly referred to as Data Pipelines, which ingests events and profile attributes from a website, mobile app, CRM, or data warehouse and makes that data immediately available for segmentation and triggers. Segments can combine behavioral signals with demographic or account-level attributes to target the right audience.$q$, $q$Supporting capabilities include A/B testing for subject lines and message content, Liquid-based templating for dynamic personalization, and reporting dashboards covering deliverability, opens, clicks, and conversion against defined goals. A REST API, webhooks, and mobile SDKs let engineering teams wire messaging directly into product code rather than managing it purely through the UI.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$the-experience$q$, $q$The Customer.io Experience$q$, 2, ARRAY[$q$Teams typically start by connecting a data source, an SDK, the API, or an integration like Segment, so that customer events and profile attributes begin flowing into Customer.io before any campaign is even built. This upfront data-connection step is central to how the product works and generally takes more initial setup effort than tools that start from a simple uploaded contact list.$q$, $q$Once data is flowing, building a first workflow inside Journeys is fairly visual and approachable, though mastering branching logic, audience filters, and Liquid templating for personalization takes real time for people without a marketing-ops or technical background. In-app guidance and documentation help close that gap, but the learning curve is noticeably steeper than with basic drag-and-drop email tools.$q$, $q$Day-to-day use tends to center on monitoring live workflows, refining segments as new events get tracked, and iterating on messaging using the built-in reporting. Teams that invest the effort in initial data setup generally find the ongoing experience of building, testing, and adjusting campaigns fast and flexible once that underlying data foundation is properly in place.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
