INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2e3ae148-915e-4e17-8568-b7b871d77ebd', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Multi-track video editing (Cut and Edit pages)$q$, $q$Two dedicated editing pages cover both fast, source-tape style trimming and a full multi-track timeline with trim tools, multi-cam sync, and text-based editing driven by a transcript.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Node-based color grading$q$, $q$The Color page offers node-based grading, waveform and vectorscope tools, and HDR grading controls used for detailed shot-by-shot color correction and creative looks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Fairlight audio post-production$q$, $q$A dedicated audio page provides multi-track mixing, ADR recording, noise reduction, and mastering scopes for finishing sound without leaving the project.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Fusion visual effects and motion graphics$q$, $q$Node-based compositing tools let editors build titles, motion graphics, and visual effects directly inside the same timeline as the edit.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Neural Engine AI tools (Studio)$q$, $q$Studio-only AI features include automatic face and object detection, speed and scene-cut analysis, and other tools that speed up otherwise manual grading and editing tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Multi-user collaboration (Studio)$q$, $q$A shared project database lets multiple editors, colorists, and sound mixers work on different parts of the same project at the same time instead of passing files back and forth.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Broad format and codec support$q$, $q$Resolve supports a wide range of camera RAW formats, ProRes, and high frame rate footage, along with multi-cam angles from mixed camera sources.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Deliver page for rendering and export$q$, $q$A dedicated delivery page handles exporting to the file formats and codecs used for web, broadcast, and disc-based distribution, including custom render presets.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Cross-platform availability$q$, $q$DaVinci Resolve runs on Mac, Windows, and Linux, letting mixed-platform teams open and work on the same project files.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$The free version already includes editing, color grading, Fusion VFX, and Fairlight audio without a subscription or time limit$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$DaVinci Resolve Studio is a one-time purchase rather than a recurring subscription, unlike many editing competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Color grading tools are among the most capable available in a mainstream editing application$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Combining editing, color, audio, and VFX in one program reduces the need to move projects between separate applications$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Runs on Mac, Windows, and Linux, giving flexibility to mixed-platform teams and individuals$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$The page-based interface and sheer number of tools create a steeper learning curve than simpler editors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Performance depends heavily on having a reasonably capable GPU, especially for Fusion effects and higher-resolution grading$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Several notable features, including some AI tools and full multi-user collaboration, are locked behind the paid Studio upgrade$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Switching from an established Adobe-based pipeline can require real migration effort for plugins and trained workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Some third-party plugins and hardware integrations common in other NLEs have smaller or less mature Resolve equivalents$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Is DaVinci Resolve really free?$q$, $q$Yes. Blackmagic Design offers a free version of DaVinci Resolve that includes multi-track editing, color grading, Fairlight audio, and Fusion visual effects, with no time limit and no required subscription. A separate paid upgrade, DaVinci Resolve Studio, adds further features on top of the free base.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$What's the difference between the free version and DaVinci Resolve Studio?$q$, $q$DaVinci Resolve Studio is a one-time paid upgrade that adds Neural Engine AI tools, additional Resolve FX and effects, support for higher resolutions and frame rates, multi-user collaboration features, and some additional noise reduction and audio tools not available in the free version.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Is DaVinci Resolve subscription-based?$q$, $q$No. The free version has no cost at all, and DaVinci Resolve Studio is purchased once as a perpetual license rather than billed monthly or yearly, which distinguishes it from subscription-based editors like Adobe Premiere Pro.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$What kind of computer do I need to run DaVinci Resolve well?$q$, $q$Resolve relies heavily on GPU acceleration for color grading, noise reduction, and Fusion effects, so a dedicated, reasonably capable graphics card matters more than a top-end CPU. Older or integrated graphics can still run the software but may struggle with heavier timelines or higher resolutions.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Can I use DaVinci Resolve just for color grading?$q$, $q$Yes. Many editors cut in a different application and bring footage into Resolve specifically for the Color page's node-based grading tools, scopes, and HDR controls, then export or round-trip the graded footage back into their original editing workflow.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Independent filmmaking and documentary editing$q$, $q$Filmmakers use Resolve to cut, color grade, and mix a project's audio within a single application, which keeps a small crew or solo editor from needing several separate tools.$q$, $q$Independent filmmakers and documentary editors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$YouTube and online content creation$q$, $q$Creators use the free version's multi-track editing, effects, and audio tools to produce regular video content without ongoing software costs.$q$, $q$YouTubers and online video creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Collaborative post-production teams$q$, $q$Studio's shared project database lets an editor, colorist, and sound mixer work on the same timeline concurrently instead of exchanging files sequentially.$q$, $q$Post-production studios and in-house production teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$Corporate and marketing video production$q$, $q$Marketing and internal video teams use Resolve to edit and finish promotional or training videos, drawing on its color and audio tools to produce a polished result in-house.$q$, $q$Corporate video and marketing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$DaVinci Resolve (Free)$q$, $q$$0$q$, $q$Free$q$, $q$["Multi-track video editing (Cut and Edit pages)","Node-based color grading with scopes","Fairlight audio editing and mixing","Fusion visual effects and motion graphics","Support for common professional camera formats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$DaVinci Resolve Studio$q$, $q$$295$q$, $q$One-time purchase$q$, $q$["Everything in the free version","Neural Engine AI tools (face and object detection, and related automation)","Additional Resolve FX and noise reduction tools","Support for higher resolutions and frame rates","Multi-user collaboration on shared projects"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DaVinci Resolve is an all-in-one post-production application from Blackmagic Design that brings video editing, color grading, visual effects, and audio mixing into a single program. It grew out of color-correction technology originally developed by da Vinci Systems, which Blackmagic Design acquired in 2009, and has since expanded far beyond color into a full editing and finishing suite used on projects ranging from YouTube videos to feature films and broadcast television.$q$, $q$The software ships in two tiers: a free version that already includes a large share of Resolve's professional toolset, and DaVinci Resolve Studio, a paid upgrade purchased once rather than rented as a subscription. Studio adds Neural Engine AI tools, extra Resolve FX, support for higher resolutions and frame rates, and features aimed at teams collaborating on the same project, including shared bins and review tools. That one-time-purchase model is one of the more distinctive things about Resolve compared with subscription-first competitors such as Adobe Premiere Pro.$q$, $q$Work in Resolve is organized into dedicated pages, including Media, Cut, Edit, Fusion, Color, Fairlight, and Deliver, each built around one stage of the post-production process. A solo editor can move between a quick cut and detailed color grading inside the same window, while a larger team can have different people working on different pages of the same shared project at the same time, which is part of why Resolve is common in both solo and studio workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$who-davinci-resolve-is-for$q$, $q$Who DaVinci Resolve Is For$q$, 2, ARRAY[$q$Colorists and cinematographers who want a serious grading tool are a natural fit, since the Color page's node-based system, scopes, and HDR grading tools rival dedicated color applications used in higher-end facilities. Editors coming from a color-heavy production background often adopt Resolve specifically for this page even when they cut in another program, then export or round-trip footage back and forth.$q$, $q$Independent filmmakers, documentary editors, and YouTubers who want a capable, cost-free editor also gravitate toward Resolve, since the free version covers multi-track editing, basic effects, and Fairlight audio without requiring any payment or account sign-up beyond the initial download. This makes it a common recommendation for creators outgrowing simpler, more limited editors and looking for room to grow.$q$, $q$Small studios and in-house video teams benefit from having editing, color, VFX, and audio in one program instead of juggling several applications, and Studio's multi-user project database makes it a reasonable choice for teams that need several people editing, grading, or mixing the same timeline concurrently rather than passing files back and forth or waiting on one another.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Creators who mainly need fast, template-driven output for social clips may find lighter, more opinionated tools a better match, since Resolve's depth and page-based workflow add a learning curve that isn't necessary for quick vertical-video turnarounds where speed matters more than fine-grained control over color or audio.$q$, $q$Teams heavily invested in Adobe's ecosystem, with existing Premiere Pro projects, After Effects compositions, and Dynamic Link workflows, may find switching costly, since moving established pipelines, third-party plugins, and trained staff over to Resolve takes real migration effort that can outweigh the benefits for some organizations, at least in the short term.$q$, $q$Editors working on older or entry-level computers should be cautious too, since Resolve leans on GPU acceleration for playback and rendering; underpowered graphics hardware can make Fusion effects, noise reduction, and higher-resolution color grading noticeably sluggish, and some Studio-only AI features specifically call for a capable, dedicated GPU to run smoothly.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$On the editing side, the Cut and Edit pages cover everything from fast, source-tape style trimming to a full multi-track timeline with trim tools, multi-cam editing, and text-based editing that lets an editor cut by working directly with a transcript rather than scrubbing through raw footage manually, which speeds up interview-heavy projects considerably.$q$, $q$The Color page provides node-based grading, scopes, HDR grading tools, and Studio-only Neural Engine features such as automatic face and object detection for targeted adjustments, alongside Fairlight's dedicated audio mixing console, ADR recording tools, noise reduction, and mastering scopes for finishing sound directly inside the same project timeline without exporting to a separate audio application.$q$, $q$Fusion adds node-based compositing and motion graphics without leaving the timeline, letting an editor build titles, tracked graphics, and simple visual effects in the same project instead of round-tripping to a separate compositing application. The Deliver page then handles exporting to the file formats and codecs used across web, broadcast, and disc-based delivery, rounding out a pipeline that can take a project from raw footage all the way to a finished, graded, mixed master ready for release.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', $q$the-davinci-resolve-experience$q$, $q$The DaVinci Resolve Experience$q$, 2, ARRAY[$q$New users typically notice the page-based layout before anything else: rather than one editing window with docked panels for everything, Resolve routes you to a purpose-built page for whichever task you're doing, which takes some adjustment for editors used to a single-window NLE but pays off once the layout becomes familiar and the keyboard shortcuts start to click.$q$, $q$Performance depends heavily on the graphics card in the system running Resolve, since color grading, noise reduction, and Fusion effects are GPU-accelerated; on well-matched hardware the software feels responsive even at higher resolutions, while older integrated graphics can bottleneck real-time playback and make heavier timelines harder to work with smoothly.$q$, $q$Blackmagic Design maintains an active user forum and publishes a detailed manual and training material, and updates to both the free and Studio versions are released fairly regularly, so features and bug fixes keep arriving well after the initial purchase or download without any added cost, which keeps the software feeling actively maintained and closely tied to feedback from its user community.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3122bcbc-f848-4a5b-bdd0-2fdc1ab47f3e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Studio IDE$q$, $q$A browser-based development environment for writing, previewing, and testing SQL and Python dbt models without local setup.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Job scheduling and orchestration$q$, $q$Managed scheduling for running transformation jobs on a recurring cadence or via triggers, with run history and alerting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Git-native version control$q$, $q$Every model, test, and configuration file lives in git, supporting branches, pull requests, and code review for data changes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Built-in testing framework$q$, $q$Schema and custom data tests catch broken assumptions (nulls, duplicates, referential integrity) before bad data reaches downstream tables.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Slim CI$q$, $q$Continuous integration that rebuilds and tests only the models affected by a pull request instead of the entire project.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$dbt Catalog and lineage graphs$q$, $q$Auto-generated, searchable documentation and column-level lineage diagrams built directly from the project's code.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Semantic Layer$q$, $q$A central place to define business metrics once and query them consistently across connected BI and analytics tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$dbt Mesh$q$, $q$Governed cross-project references that let separate teams own and publish their own dbt projects while sharing models.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$dbt Copilot$q$, $q$An AI assistant built into the Studio IDE that can generate SQL, tests, documentation, and semantic definitions from prompts.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Multi-warehouse support$q$, $q$Adapters connect dbt Cloud to warehouses and engines including Snowflake, BigQuery, Databricks, and Redshift.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Free Developer plan lets individuals learn and prototype dbt without a credit card$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Testing, documentation, and version control are built into the core workflow rather than bolted on$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Broad support for major cloud warehouses (Snowflake, BigQuery, Databricks, Redshift) and a large open-source community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Semantic Layer and Catalog give teams one consistent source of truth for metrics and lineage$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Slim CI and git-native workflows bring standard software engineering practices to analytics changes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Cost jumps meaningfully once a team grows past the single-seat free Developer plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Usage-based billing on successful models built can be harder to forecast than a flat per-seat fee$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Requires working SQL (or Python) skills; not usable by non-technical business users on their own$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Governance features like dbt Mesh and advanced Semantic Layer access are reserved for higher, custom-priced tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Newer additions such as Copilot, Canvas, and Insights are still maturing relative to dbt's long-standing core modeling features$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$What is the difference between dbt Core and dbt Cloud?$q$, $q$dbt Core is the free, open-source command-line engine that compiles and runs dbt projects. dbt Cloud is dbt Labs' managed platform built on top of that same engine, adding a hosted browser IDE, job scheduling, CI/CD, documentation hosting, the Semantic Layer, dbt Mesh, and the dbt Copilot AI assistant.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Is dbt Cloud free?$q$, $q$dbt Cloud has a free Developer plan for a single user with a capped number of model runs per month. Paid plans start with the Starter tier at a per-seat monthly price, and Enterprise and Enterprise+ tiers are custom-priced through sales.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$What data warehouses does dbt Cloud support?$q$, $q$dbt Cloud connects to major cloud data platforms including Snowflake, Google BigQuery, Databricks, and Amazon Redshift, among others, through dbt's adapter ecosystem.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Does dbt Cloud require coding skills?$q$, $q$Yes. dbt models are written in SQL (optionally templated with Jinja) or Python code, so using dbt Cloud effectively requires SQL proficiency and a basic understanding of software development concepts like version control.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$What is dbt Copilot?$q$, $q$dbt Copilot is dbt Cloud's built-in AI assistant, available on paid plans, that can generate SQL models, tests, documentation, and semantic definitions from natural-language prompts inside the Studio IDE.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Standardizing SQL transformations$q$, $q$Analytics engineering teams replace ad hoc, undocumented SQL scripts with modular, tested, version-controlled dbt models.$q$, $q$Analytics engineers and data teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$CI/CD for data pipelines$q$, $q$Data platform teams add automated testing and pull-request checks to transformation code before it reaches production tables.$q$, $q$Data platform and DataOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Multi-team data governance$q$, $q$Enterprises with several business units use dbt Mesh and the Semantic Layer to let teams own their own models while sharing consistent, governed metrics.$q$, $q$Enterprise data organizations$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Learning analytics engineering$q$, $q$Individuals and students use the free Developer plan to learn SQL-based data modeling, testing, and documentation practices.$q$, $q$Individual analysts and learners$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Developer$q$, $q$Free$q$, $q$N/A$q$, $q$["1 developer seat","1 project","Browser-based Studio IDE","Job scheduling","Capped successful model runs per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Starter$q$, $q$$100/seat/month$q$, $q$Monthly$q$, $q$["Up to 5 developer seats","1 project","Basic Catalog and Semantic Layer","dbt Copilot code generation","API access","14-day free trial available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, $q$["Custom seat count","Up to 30 projects","Advanced Catalog, Semantic Layer, and dbt Mesh","dbt Canvas and Insights","Dedicated account management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Enterprise+$q$, $q$Custom pricing$q$, $q$Annual$q$, $q$["Unlimited projects","All Enterprise features","PrivateLink and IP restrictions","Rollback support","Hybrid project deployment"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$dbt Cloud is the managed, hosted version of dbt (data build tool), built by dbt Labs, the Philadelphia-based company founded in 2016 that was originally known as Fishtown Analytics. dbt itself pioneered the practice now commonly called "analytics engineering": applying software engineering discipline, such as version control, automated testing, modularity, and documentation, to the SQL transformations that turn raw warehouse data into clean, analysis-ready tables that downstream reports and dashboards can rely on.$q$, $q$The core idea behind dbt is the "T" in ELT. Data is extracted from source systems and loaded into a cloud warehouse first, and dbt handles the transformation step by letting analysts and engineers write modular SQL (or Python) models, define tests against the resulting tables, and generate documentation and lineage graphs directly from the codebase. This makes dbt fundamentally a transformation and workflow tool, not a data ingestion, orchestration-from-scratch, or BI visualization tool.$q$, $q$dbt Core, the underlying engine, is free and open source and can be run from the command line by anyone with their own compute and scheduling setup. dbt Cloud wraps that same engine in a browser-based IDE, managed job scheduling, CI/CD, hosted documentation, a Semantic Layer, dbt Mesh for multi-project governance, and an AI assistant called dbt Copilot, so teams do not have to self-host orchestration and IDE infrastructure themselves.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$who-dbt-cloud-is-for$q$, $q$Who dbt Cloud Is For$q$, 2, ARRAY[$q$dbt Cloud is built for analytics engineers, data engineers, and data analysts who are comfortable writing SQL and want that SQL to live in a version-controlled, testable codebase rather than in scattered BI-tool queries or ad hoc scripts. It fits naturally into teams already using a cloud data warehouse such as Snowflake, BigQuery, Databricks, or Redshift and looking to formalize how that warehouse's raw data gets modeled.$q$, $q$It also suits data teams and platform leads who want scheduled, monitored transformation jobs and continuous integration checks on data changes without having to stand up and maintain their own orchestrator (like Airflow) and IDE tooling. Teams that need to hand off trustworthy, documented datasets to business stakeholders benefit from the automatically generated documentation and lineage graphs, which reduce the back-and-forth of explaining where a metric comes from.$q$, $q$Larger organizations with multiple domains or business units are a strong fit for the Enterprise tiers, since dbt Mesh allows separate teams to own and publish their own dbt projects while referencing each other's models in a governed way, and the Semantic Layer gives the whole company one place to define metrics consistently across BI tools instead of redefining the same calculation in every dashboard.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Non-technical users, or teams without anyone comfortable writing SQL, are not the intended audience. dbt Cloud is not a drag-and-drop data preparation tool; every model is written as SQL (with optional Jinja templating) or Python code, so some analytics engineering skill is required to get value from it, and there is a real onboarding curve for people used to purely visual ETL tools.$q$, $q$Teams running only a handful of one-off queries or a single small reporting project may find dbt's testing, documentation, and version-control overhead unnecessary. A warehouse's native SQL console, a spreadsheet, or a lightweight script can be faster for genuinely small, disposable analysis where nobody else needs to reuse or audit the logic later.$q$, $q$Very cost-sensitive teams that need more than one seat should budget carefully: the Developer plan is free but limited to a single user and a capped number of model runs per month, and moving to the Starter plan introduces a per-seat monthly fee plus usage-based charges for models built beyond the included allowance. Teams that only need basic scheduling, and are willing to take on more DevOps work, may find running open-source dbt Core with their own orchestrator more economical over time.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The browser-based Studio IDE lets users write and preview compiled SQL models, run and debug transformations against live warehouse data, and commit changes to git without leaving the browser or installing local tooling. Built-in job scheduling and orchestration runs transformation jobs on a cron-like cadence or via API and webhook triggers, and native git integration keeps every model change under version control from day one.$q$, $q$dbt Cloud includes a testing framework for validating data quality (schema tests like not-null and uniqueness, plus custom SQL-based data tests), a Catalog that auto-generates searchable documentation and column-level lineage graphs from the project itself, and Slim CI, which only rebuilds and tests models affected by a given pull request rather than the whole project, keeping validation fast even on large codebases.$q$, $q$Higher tiers add the Semantic Layer for defining metrics once and querying them consistently from multiple BI tools, dbt Mesh for governed cross-project references between teams, dbt Copilot, an AI assistant that can draft SQL, tests, and documentation from natural-language prompts, and dbt Canvas, a visual interface for building and reviewing pipelines alongside the underlying code.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$the-dbt-cloud-experience$q$, $q$The dbt Cloud Experience$q$, 2, ARRAY[$q$Day to day, most work happens in the Studio IDE: editing .sql model files, previewing the compiled query and a sample of the resulting data, and writing or running tests before committing changes on a feature branch. The workflow deliberately mirrors software development rather than a typical BI or spreadsheet workflow, down to branching, diffing, and reviewing changes before they merge.$q$, $q$Once merged, scheduled jobs run the transformation pipeline automatically, refreshing documentation and lineage graphs as models change, and failures or job status can be routed to Slack or email so the team knows immediately if a pipeline breaks. Pull requests trigger CI checks that validate changes before they reach production models, catching broken logic before it reaches a dashboard.$q$, $q$Overall, the experience feels like applying pull requests, code review, and automated testing to a data warehouse rather than treating transformations as one-off scripts. That engineering-first philosophy is dbt's biggest differentiator, and it is also why the learning curve is steeper for people coming from purely point-and-click BI or ETL tools, though most SQL-literate analysts adapt within a few projects.$q$]::text[], 4);
